#include <stdio.h>
#include <inttypes.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t X;
        scanf("%" PRId64, &X);
        int r = X % 4;
        if (r == 0) printf("North\n");
        else if (r == 1) printf("East\n");
        else if (r == 2) printf("South\n");
        else printf("West\n");
    }
    return 0;
}

