code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int i = 0; i < T; i++) {
            long X = Long.parseLong(br.readLine().trim());
            int r = (int)(X % 4);
            if (r == 0) out.append("North\n");
            else if (r == 1) out.append("East\n");
            else if (r == 2) out.append("South\n");
            else out.append("West\n");
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        x = int(data[i])
        r = x % 4
        if r == 0:
            out.append('North')
        elif r == 1:
            out.append('East')
        elif r == 2:
            out.append('South')
        else:
            out.append('West')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

